// uiCapYears is the date-picker cap the costco.com Orders & Returns UI exposes.
const uiCapYears = 2

// depthProbe is one step of the backward date-range walk.
type depthProbe struct {
	YearsBack       int    `json:"yearsBack"`
	StartDate       string `json:"startDate"`
	ReceiptCount    int    `json:"receiptCount"`
	EarliestReceipt string `json:"earliestReceipt,omitempty"`
}

// depthResult is the history-depth report.
type depthResult struct {
	UICapYears        int          `json:"uiCapYears"`
	Probes            []depthProbe `json:"probes"`
	EarliestReceipt   string       `json:"earliestReceipt,omitempty"`
	ServedBeyondUICap bool         `json:"servedBeyondUiCap"`
	FloorReached      bool         `json:"floorReached"`
	Note              string       `json:"note"`
}

// depthLadder returns the years-back steps to probe, capped at maxYears and
// thinned when running under live-dogfood to fit the per-command timeout.
func depthLadder(maxYears int, dogfood bool) []int {
	if maxYears < uiCapYears {
		maxYears = uiCapYears
	}
	base := []int{2, 3, 5, 8, 12, 16, 20}
	if dogfood {
		base = []int{2, 5}
	}
	out := []int{}
	for _, y := range base {
		if y <= maxYears {
			out = append(out, y)
		}
	}
	// Always include the cap itself so the widest bound is probed.
	if len(out) == 0 || out[len(out)-1] != maxYears {
		out = append(out, maxYears)
	}
	return out
}

// analyzeDepth derives the floor finding from the probe series. earliestOf is
// the oldest receipt date seen anywhere. The floor is "reached" when the two
// widest probes return the same earliest receipt — widening the window stopped
// surfacing older data, so that date is the true floor (account or API).
func analyzeDepth(probes []depthProbe, uiFloor string) depthResult {
	res := depthResult{UICapYears: uiCapYears, Probes: probes}
	earliest := ""
	for _, p := range probes {
		if p.EarliestReceipt == "" {
			continue
		}
		if earliest == "" || p.EarliestReceipt < earliest {
			earliest = p.EarliestReceipt
		}
	}
	res.EarliestReceipt = earliest
	res.ServedBeyondUICap = earliest != "" && earliest < uiFloor

	withData := []depthProbe{}
	for _, p := range probes {
		if p.EarliestReceipt != "" {
			withData = append(withData, p)
		}
	}
	if len(withData) >= 2 {
		a := withData[len(withData)-2]
		b := withData[len(withData)-1]
		res.FloorReached = a.EarliestReceipt == b.EarliestReceipt
	} else if len(withData) == 1 {
		res.FloorReached = true
	}

	switch {
	case earliest == "":
		res.Note = "No receipts returned in any probed window. If you expect history, confirm your token is valid (run doctor) and that this membership has purchases."
	case res.FloorReached && res.ServedBeyondUICap:
		res.Note = fmt.Sprintf("API served receipts back to %s — older than the website's %d-year UI cap. Widening the window stopped surfacing older receipts, so %s is your account's floor (your first receipt or the API's retention limit).", earliest, uiCapYears, earliest)
	case res.FloorReached:
		res.Note = fmt.Sprintf("Earliest receipt is %s and widening the window surfaced nothing older, so that is your account floor. It falls within the %d-year window the UI already shows.", earliest, uiCapYears)
	case res.ServedBeyondUICap:
		res.Note = fmt.Sprintf("API served receipts back to %s, past the %d-year UI cap, and the widest probe still returned older data — raise --max-years to keep searching for the true floor.", earliest, uiCapYears)
	default:
		res.Note = fmt.Sprintf("Earliest receipt is %s. Raise --max-years to probe further back.", earliest)
	}
	return res
}

func newNovelHistoryDepthCmd(flags *rootFlags) *cobra.Command {
	var maxYears int
	cmd := &cobra.Command{
		Use:   "history-depth",
		Short: "Discover how far back your Costco receipts actually go, past the website's 2-year UI cap.",
		Long: strings.Trim(`
Discover how far back the Costco API actually serves your receipts.

The website date picker caps at 2 years, but the receipts API accepts any
startDate. This command steps the start date backward in widening windows and
reports where your earliest receipt stops moving — the true floor for your
account (either your first purchase or the API's retention limit).`, "\n"),
		Example:     "  costco-pp-cli history-depth --max-years 16 --json",
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), "would probe receipt history depth by stepping startDate backward")
				return nil
			}
			if maxYears <= 0 {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("--max-years must be positive"))
			}
			ctx, cancel := boundCtx(cmd.Context(), flags)
			defer cancel()
			end := todayDate()
			uiFloor := time.Now().AddDate(-uiCapYears, 0, 0).Format(dateLayout)
			ladder := depthLadder(maxYears, cliutil.IsDogfoodEnv())
			probes := make([]depthProbe, 0, len(ladder))
			for _, yb := range ladder {
				start := time.Now().AddDate(-yb, 0, 0).Format(dateLayout)
				receipts, err := fetchReceipts(ctx, flags, start, end)
				if err != nil {
					return classifyAPIError(err, flags)
				}
				probes = append(probes, depthProbe{
					YearsBack:       yb,
					StartDate:       start,
					ReceiptCount:    len(receipts),
					EarliestReceipt: earliestDate(receipts),
				})
			}
			result := analyzeDepth(probes, uiFloor)
			b, err := json.Marshal(result)
			if err != nil {
				return err
			}
			return printOutputWithFlags(cmd.OutOrStdout(), b, flags)
		},
	}
	cmd.Flags().IntVar(&maxYears, "max-years", 16, "Maximum years back to probe")
	return cmd
}

// earliestDate returns the minimum transactionDate across receipts ("" if none).
func earliestDate(receipts []costcoReceipt) string {
	earliest := ""
	for _, r := range receipts {
		if r.TransactionDate == "" {
			continue
		}
		if earliest == "" || r.TransactionDate < earliest {
			earliest = r.TransactionDate
		}
	}
	return earliest
}
